import React, { useState, useEffect } from "react";
import axios from "axios";

const Bill = () => {
  const [bills, setBills] = useState([]);
  const [form, setForm] = useState({
    MaHD: "",
    PhongSo: "",
    NgayNhan: "",
    NgayTra: "",
    GiaPhong: "",
    TongDV: "",
    TongTien: "",
    PhuongThucTT: "",
  });
  const [report, setReport] = useState(null);

  const apiBase = "http://localhost:5000/api/bill";

  // Lấy tất cả hóa đơn
  const fetchAllBills = async () => {
    try {
      const res = await axios.get(`${apiBase}/allbills`);
      const sorted = res.data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setBills(sorted);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  useEffect(() => {
    fetchAllBills();
  }, []);

  // Hàm tính số ngày ở
  const calcDays = (nhan, tra) => {
    if (!nhan || !tra) return 0;
    const start = new Date(nhan);
    const end = new Date(tra);
    const diff = (end - start) / (1000 * 60 * 60 * 24);
    return diff > 0 ? diff : 0;
  };

  // Hàm tính tổng tiền
  const calcTongTien = (nhan, tra, giaPhong, tongDV) => {
    const soNgay = calcDays(nhan, tra);
    const gia = Number(giaPhong) || 0;
    const dv = Number(tongDV) || 0;
    return soNgay * gia + dv;
  };

  // Thêm/cập nhật
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const data = {
        ...form,
        TongTien: calcTongTien(form.NgayNhan, form.NgayTra, form.GiaPhong, form.TongDV),
      };

      const exists = bills.find((b) => b.MaHD === form.MaHD);
      if (exists) {
        await axios.put(`${apiBase}/updatebill`, data);
        alert("Cập nhật hóa đơn thành công");
      } else {
        await axios.post(`${apiBase}/addbill`, data);
        alert("Thêm hóa đơn thành công");
      }
      setForm({
        MaHD: "",
        PhongSo: "",
        NgayNhan: "",
        NgayTra: "",
        GiaPhong: "",
        TongDV: "",
        TongTien: "",
        PhuongThucTT: "",
      });
      fetchAllBills();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Xóa hóa đơn
  const handleDelete = async (MaHD) => {
    if (!window.confirm("Bạn có chắc muốn xóa hóa đơn này?")) return;
    try {
      await axios.delete(`${apiBase}/deletebill`, { data: { MaHD } });
      fetchAllBills();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Báo cáo
  const fetchReport = async () => {
    try {
      const res = await axios.get(`${apiBase}/reportbill`);
      setReport(res.data);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Quản lý hóa đơn</h1>

      {/* Form thêm/sửa hóa đơn */}
      <form className="mb-4 space-y-2" onSubmit={handleSubmit}>
        <input
          placeholder="Mã HD"
          value={form.MaHD}
          onChange={(e) => setForm({ ...form, MaHD: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Phòng số"
          value={form.PhongSo}
          onChange={(e) => setForm({ ...form, PhongSo: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          type="date"
          value={form.NgayNhan}
          onChange={(e) => setForm({ ...form, NgayNhan: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          type="date"
          value={form.NgayTra}
          onChange={(e) => setForm({ ...form, NgayTra: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          type="number"
          placeholder="Giá phòng"
          value={form.GiaPhong}
          onChange={(e) => setForm({ ...form, GiaPhong: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          type="number"
          placeholder="Tổng DV"
          value={form.TongDV}
          onChange={(e) => setForm({ ...form, TongDV: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Phương thức TT"
          value={form.PhuongThucTT}
          onChange={(e) => setForm({ ...form, PhuongThucTT: e.target.value })}
          className="border p-2 w-full"
        />

        {/* Hiển thị tổng tiền tính tự động */}
        <div className="p-2 bg-gray-100 rounded">
          Số ngày ở: <b>{calcDays(form.NgayNhan, form.NgayTra)}</b> <br />
          Tổng tiền:{" "}
          <b>
            {calcTongTien(
              form.NgayNhan,
              form.NgayTra,
              form.GiaPhong,
              form.TongDV
            ).toLocaleString("vi-VN")}{" "}
            đ
          </b>
        </div>

        <button type="submit" className="bg-blue-500 text-white px-4 py-2 rounded">
          {bills.find((b) => b.MaHD === form.MaHD) ? "Cập nhật" : "Thêm hóa đơn"}
        </button>
      </form>

      {/* Danh sách hóa đơn */}
      <table className="border w-full text-left mb-4">
        <thead>
          <tr className="bg-gray-200">
            <th className="border px-2 py-1">Mã HD</th>
            <th className="border px-2 py-1">Phòng số</th>
            <th className="border px-2 py-1">Ngày nhận</th>
            <th className="border px-2 py-1">Ngày trả</th>
            <th className="border px-2 py-1">Số ngày ở</th>
            <th className="border px-2 py-1">Giá phòng</th>
            <th className="border px-2 py-1">Tổng DV</th>
            <th className="border px-2 py-1">Tổng tiền</th>
            <th className="border px-2 py-1">Phương thức TT</th>
            <th className="border px-2 py-1">Hành động</th>
          </tr>
        </thead>
        <tbody>
          {bills.map((b) => (
            <tr key={b.MaHD}>
              <td className="border px-2 py-1">{b.MaHD}</td>
              <td className="border px-2 py-1">{b.PhongSo}</td>
              <td className="border px-2 py-1">{b.NgayNhan}</td>
              <td className="border px-2 py-1">{b.NgayTra}</td>
              <td className="border px-2 py-1">{calcDays(b.NgayNhan, b.NgayTra)}</td>
              <td className="border px-2 py-1">{b.GiaPhong}</td>
              <td className="border px-2 py-1">{b.TongDV}</td>
              <td className="border px-2 py-1">{b.TongTien}</td>
              <td className="border px-2 py-1">{b.PhuongThucTT}</td>
              <td className="border px-2 py-1">
                <button
                  onClick={() => setForm(b)}
                  className="bg-yellow-400 px-2 py-1 mr-2 rounded"
                >
                  Sửa
                </button>
                <button
                  onClick={() => handleDelete(b.MaHD)}
                  className="bg-red-500 px-2 py-1 rounded text-white"
                >
                  Xóa
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Báo cáo */}
      <div>
        <button
          onClick={fetchReport}
          className="bg-purple-500 text-white px-4 py-2 rounded mb-2"
        >
          Xem báo cáo
        </button>
        {report && (
          <pre className="bg-gray-100 p-2">{JSON.stringify(report, null, 2)}</pre>
        )}
      </div>
    </div>
  );
};

export default Bill;
